chart.options:
chart: {
  type: 'funnel',
  height: 400,
  dropShadow: {
    enabled: true,
  },
},
plotOptions: {
  funnel: {
    shape: 'trapezoid',
    lastShape: 'flat',
  },
  bar: {
    barHeight: '90%',
    distributed: true,
  },
},
colors: [
  '#3b82f6',
  '#00a3f4',
  '#00b7b8',
  '#00c161',
  '#93bd00',
  '#ffa600'
],
dataLabels: {
  enabled: true,
  formatter: function (val, opt) {
    return opt.w.globals.labels[opt.dataPointIndex] + ': ' + val
  },
  style: {
    colors: ['#fff'],
    fontSize: '14px',
    fontWeight: 600,
  },
},
title: {
  text: 'Sales Funnel — Trapezoid',
  align: 'middle',
},
xaxis: {
  categories: [
    'Visits',
    'Signups',
    'Activated',
    'Engaged',
    'Trial',
    'Paid',
  ],
},
legend: {
  show: false,
},
